## Step 3: Adding Once and RemoveAll
Let's extend with two more useful methods:
```typescript
class TypedEmitter<Events extends EventMap> {
  private handlers = new Map<keyof Events, EventHandler[]>();

  on<K extends keyof Events>(event: K, handler: EventHandler<Events[K]>): void {
    const existing = this.handlers.get(event) ?? [];
    existing.push(handler as EventHandler);
    this.handlers.set(event, existing);
  }

  once<K extends keyof Events>(event: K, handler: EventHandler<Events[K]>): void {
    const wrapper = ((payload: Events[K]) => {
      handler(payload);
      this.off(event, wrapper as EventHandler<Events[K]>);
    }) as EventHandler;

    const existing = this.handlers.get(event) ?? [];
    existing.push(wrapper);
    this.handlers.set(event, existing);
  }

  off<K extends keyof Events>(event: K, handler: EventHandler<Events[K]>): void {
    const existing = this.handlers.get(event) ?? [];
    this.handlers.set(
      event,
      existing.filter((h) => h !== handler)
    );
  }

  removeAll<K extends keyof Events>(event?: K): void {
    if (event) {
      this.handlers.delete(event);
    } else {
      this.handlers.clear();
    }
  }

  emit<K extends keyof Events>(event: K, payload: Events[K]): void {
    const existing = this.handlers.get(event) ?? [];
    for (const handler of existing) {
      handler(payload);
    }
  }
}
```
